class DataclassNode(Node):
    def __init__(self, *pos_args, label=None, **kwargs):
        super().__init__(label or cls.__name__)

        for field in fields(cls):
            port_type = field.type if field.type is not MISSING else None
            has_default = field.default is not MISSING
            default = field.default if has_default else None
            if getattr(field, 'default_factory', MISSING) is not MISSING:  # type: ignore
                default = field.default_factory()
                has_default = True
            self.add_input(field.name, port_type=port_type, default=default)
            if has_default:
                self.inputs[field.name]._value = default
                self.inputs[field.name].ready = True
            else:
                self.inputs[field.name]._value = NotData
                self.inputs[field.name].ready = False

        self.add_output('output', port_type=cls)
        try:
            self._source = inspect.getsource(cls)
        except Exception:
            self._source = None
        if hasattr(cls, '__module__'):
            self._module_path = f"{cls.__module__}.{cls.__name__}"
        else:
            self._module_path = cls.__name__

        for arg_val, field in zip(pos_args, fields(cls)):
            self.inputs[field.name].value = arg_val

        for key, val in kwargs.items():
            if key in self.inputs:
                self.inputs[key].value = val
            else:
                raise ValueError(f'Input port \"{key}\" does not exist on node \"{self.label}\"')

    def execute(self):
        inputs = {}
        for field in fields(cls):
            port = self.inputs[field.name]
            inputs[field.name] = port.value if port.ready else port.default

        instance = cls(**inputs)
        self.outputs['output'].set_value(instance)

@as_function_node
def RelaxLoop(
        mode: str | RelaxMode,
        calculator: Node,
        opt: Node,
        structures: list[Atoms]
) -> list[Atoms]:
    from tqdm.auto import tqdm
    mode = RelaxMode(mode)
    relaxed_structures = []
    for structure in tqdm(structures, desc=f"Relax {mode.value}"):
        relaxed_structures.append(
                Relax(mode, calculator, opt, structure).pull()
        )
    return relaxed_structures

